'use strict';
const MISSIONS=[
{code:'DS-01',module:'Introdução',title:'A nuvem não é um computador só',rank:'Trainee',concepts:['mensagens','concorrência','relógio global','falhas parciais'],brief:'Nebula Cloud recebeu reclamações: alguns usuários acham que o sistema é uma máquina única. Seu trabalho é mostrar que cada nó é independente e coordena ações apenas por mensagens.',terminal:'model: distributed-system\ncomponents: hardware/software in networked computers\ncoordination: message passing\nrisks: concurrency + no_global_clock + independent_failures',nodes:[['Cliente',15,50,'💻','live'],['API EU',42,25,'⚙️','live'],['API US',42,75,'⚙️','warn'],['DB',75,50,'🗄️','live']],links:[[0,1],[0,2],[1,3],[2,3]],steps:[{q:'Qual afirmação define melhor o cenário?',opts:['Componentes em computadores ligados em rede que coordenam ações por troca de mensagens.','Um programa local com várias funções chamadas diretamente por ponteiros.','Um sistema que sempre possui relógio global perfeito.','Um sistema onde todas as falhas acontecem ao mesmo tempo.'],a:0,why:'Um sistema distribuído combina componentes em computadores de rede que se coordenam por mensagens. A dificuldade vem da concorrência, da ausência de relógio global e de falhas independentes.'},{q:'Qual é uma boa razão para tornar o sistema distribuído?',opts:['Compartilhar recursos, aumentar confiabilidade, melhorar performance por proximidade e resolver problemas grandes demais para um nó.','Eliminar completamente falhas de comunicação.','Garantir que todos os nós tenham o mesmo hardware.','Evitar qualquer necessidade de middleware.'],a:0,why:'O material destaca partilha de recursos, confiabilidade, performance e escala como motivações. Distribuição não remove falhas; ela exige tratá-las.'}]},
{code:'DS-02',module:'Desafios',title:'Transparência sem ilusão',rank:'Engineer I',concepts:['heterogeneidade','openness','scalability','transparency'],brief:'Você precisa migrar um serviço para outro datacenter sem que o cliente saiba onde ele está. Ao mesmo tempo, a plataforma precisa continuar aberta, escalável e segura.',terminal:'client.call("/catalog") -> service_ref\nmove service EU -> US\nexpected: same operation, no location awareness',nodes:[['Cliente',12,50,'📱','live'],['Proxy',35,50,'🧭','live'],['Service EU',62,30,'📦','warn'],['Service US',78,70,'📦','live']],links:[[0,1],[1,2,'bad'],[1,3]],steps:[{q:'Quando o cliente usa a mesma operação sem saber se o recurso está local ou remoto, isso é:',opts:['Access transparency.','Failure transparency.','Scaling transparency.','Byzantine transparency.'],a:0,why:'Access transparency significa esconder diferenças entre acesso local e remoto, oferecendo operações idênticas.'},{q:'Quando o cliente não precisa saber em que máquina/datacenter está o serviço, isso é:',opts:['Location transparency.','Concurrency transparency.','Security transparency.','Physical transparency.'],a:0,why:'Location transparency oculta a localização física ou de rede do recurso.'},{q:'Qual desafio aparece quando muitos usuários entram no sistema?',opts:['Scalability: evitar gargalos, controlar custo e preservar desempenho.','O sistema deixa de ser distribuído automaticamente.','O middleware se torna desnecessário.','Todos os nós passam a compartilhar memória física.'],a:0,why:'Escalabilidade exige manter eficiência com mais usuários e recursos, evitando gargalos e esgotamento de recursos.'}]},
{code:'DS-03',module:'Arquiteturas',title:'Monte o e-commerce distribuído',rank:'Architect I',concepts:['client-server','P2P','two-tier','three-tier','proxy'],brief:'A Black Friday está chegando. Escolha a arquitetura correta para separar interface, lógica de negócio e dados. Depois identifique quando usar proxy ou P2P.',terminal:'target architecture:\nTier 1: user view/control\nTier 2: application logic\nTier 3: database manager',nodes:[['Cliente',12,48,'🛒','live'],['Web/API',39,48,'🌐','live'],['App Logic',62,48,'⚙️','live'],['Database',84,48,'🗄️','live']],links:[[0,1],[1,2],[2,3]],steps:[{q:'Cliente → lógica de aplicação → banco de dados representa melhor:',opts:['Three-tier architecture.','Peer-to-peer puro.','Sistema sem camadas.','Distributed shared memory.'],a:0,why:'A arquitetura three-tier separa visualização/controle, lógica da aplicação e gerenciador de banco de dados.'},{q:'Um servidor intermediário que recebe requisições do cliente e busca respostas no servidor real é:',opts:['Proxy server.','Tuple space.','Byzantine node.','Lamport clock.'],a:0,why:'O proxy fica entre cliente e servidor e pode mediar, cachear, filtrar ou encaminhar requisições.'},{q:'Quando todos os nós têm capacidades semelhantes e compartilham responsabilidades, temos:',opts:['Peer-to-peer.','Client-server centralizado.','Thin client obrigatório.','SOAP.'],a:0,why:'Em P2P, os peers contribuem recursos e assumem capacidades/responsabilidades semelhantes.'}]},
{code:'DS-04',module:'Comunicação',title:'O chat travou no handshake',rank:'Communication Engineer',concepts:['OSI','TCP/IP','sockets','TCP'],brief:'O chat da Nebula falha antes de enviar dados. Você precisa entender o caminho da comunicação e a sequência básica do socket/TCP.',terminal:'tcp trace:\nclient -> server: SYN\nserver -> client: SYN-ACK\nclient -> server: ACK\nclient -> server: DATA',nodes:[['Client',20,50,'💬','live'],['Network',50,50,'🌐','live'],['Server',80,50,'🖥️','live']],links:[[0,1],[1,2]],packets:['cyan','amber'],steps:[{q:'A ordem correta no uso básico de sockets é:',opts:['Abrir socket; abrir streams; ler/escrever conforme protocolo; fechar streams; fechar socket.','Ler dados; abrir socket; fechar servidor; criar IP.','Abrir banco; mandar ACK; converter XML; fechar DNS.','Começar pelo FIN e depois enviar SYN.'],a:0,why:'Os slides listam exatamente esses passos para sockets: abrir socket, streams, ler/escrever e fechar.'},{q:'No TCP, antes do envio de dados normalmente ocorre:',opts:['SYN, SYN-ACK, ACK.','GET, PUT, DELETE.','publish, subscribe, notify.','write, read, take.'],a:0,why:'O handshake TCP estabelece a conexão com SYN → SYN-ACK → ACK antes do fluxo de dados.'},{q:'No modelo TCP/IP, TCP e UDP pertencem principalmente à camada:',opts:['Transporte.','Aplicação.','Física.','Data link.'],a:0,why:'TCP e UDP aparecem na camada de transporte no modelo TCP/IP.'}]},
{code:'DS-05',module:'Invocação remota',title:'O método está do outro lado da rede',rank:'RPC/RMI Specialist',concepts:['RPC','RMI','latência','remote reference'],brief:'Um objeto Conta Bancária vive em outro servidor. A chamada parece local, mas envolve referência remota, interface, rede, falhas e latência.',terminal:'Conta conta = lookup("bank/Conta#42")\nconta.deposit(100)\nremote_latency = 5ms\npossible_exceptions = timeout | message_loss | server_crash',nodes:[['Client Obj',18,50,'🧩','live'],['Stub/Proxy',40,50,'🔌','live'],['Network',60,50,'🌐','warn'],['Remote Object',82,50,'🏦','live']],links:[[0,1],[1,2],[2,3]],steps:[{q:'Em objetos distribuídos, a referência remota normalmente contém:',opts:['Informação de localização, segurança e tipo do objeto.','Apenas um ponteiro local de memória.','Somente a senha do usuário.','O clock global do sistema.'],a:0,why:'Referências distribuídas são maiores e carregam informação de localização, segurança e tipo.'},{q:'Por que interfaces distribuídas devem ser coarse-grained?',opts:['Porque chamadas remotas têm latência maior que chamadas locais e não devem ser excessivamente frequentes.','Porque chamadas remotas são sempre mais rápidas que locais.','Porque não existe concorrência em objetos remotos.','Porque RMI elimina falhas de rede.'],a:0,why:'Chamada local é muito rápida; chamada remota pode levar milissegundos. Por isso operações remotas devem executar tarefas maiores.'},{q:'Uma falha típica em uma invocação remota é:',opts:['Perda de mensagem, timeout ou crash do processo remoto.','Erro de sintaxe CSS.','Mudança automática de arquitetura para P2P.','Garantia de execução exatamente uma vez sem validação.'],a:0,why:'O material destaca que requisições distribuídas falham mais que chamadas locais; o cliente precisa validar se o servidor executou.'}]},
{code:'DS-06',module:'Comunicação indireta',title:'Desacople ou colapse',rank:'Messaging Engineer',concepts:['space uncoupling','time uncoupling','group communication','pub-sub'],brief:'Na Nebula News, produtores de eventos não podem conhecer todos os assinantes. O sistema precisa desacoplar espaço e tempo usando broker, grupos e publish-subscribe.',terminal:'publisher -> event_service.publish(e1)\nsubscriber A: subscribe(topic=alerts)\nsubscriber B: subscribe(topic=alerts)\nevent_service -> notify(e1)',nodes:[['Publisher',12,45,'📣','live'],['Broker',45,45,'📬','live'],['Sub A',78,25,'👤','live'],['Sub B',78,48,'👤','live'],['Sub C',78,72,'👤','warn']],links:[[0,1],[1,2],[1,3],[1,4]],steps:[{q:'Quando o emissor não precisa saber a identidade do receptor, há:',opts:['Space uncoupling.','Crash-stop.','Reliable link.','WSDL.'],a:0,why:'Space uncoupling remove a necessidade de o emissor conhecer o receptor.'},{q:'Quando emissor e receptor podem ter vidas independentes, há:',opts:['Time uncoupling.','Location transparency apenas.','TCP handshake.','Byzantine failure.'],a:0,why:'Time uncoupling permite que emissor e receptor não estejam ativos ao mesmo tempo.'},{q:'Publish-subscribe é melhor descrito como:',opts:['Publicadores enviam eventos para um serviço; assinantes recebem notificações conforme suas subscriptions.','Um ponteiro local compartilhado por processos.','Um protocolo obrigatório baseado somente em SOAP.','Um algoritmo onde todos os nós devem ser maliciosos.'],a:0,why:'Pub-sub é um paradigma um-para-muitos com eventos, subscriptions e serviço de disseminação.'}]},
{code:'DS-07',module:'Filas e espaços',title:'Black Friday na fila',rank:'Queue Operator',concepts:['message queues','FIFO','DSM','tuple spaces'],brief:'Durante a Black Friday, pedidos chegam mais rápido do que os consumidores processam. Sem fila, a API cai. Com fila, produtores e consumidores desacoplam.',terminal:'queue: orders\npolicy: FIFO\nmessage = {destination, metadata, body}\nconsumer.receive(blocking|poll|notify)',nodes:[['Producer 1',12,28,'🛍️','live'],['Producer 2',12,70,'🛍️','live'],['Queue',45,50,'📥','live'],['Worker A',78,35,'⚙️','live'],['Worker B',78,65,'⚙️','warn']],links:[[0,2],[1,2],[2,3],[2,4]],steps:[{q:'Message queues oferecem principalmente:',opts:['Serviço ponto-a-ponto via fila, com produtores enviando e consumidores removendo mensagens.','Compartilhamento físico de RAM entre máquinas.','Consenso bizantino por padrão.','Um único broadcast sem armazenamento.'],a:0,why:'Filas usam uma queue como indirection: produtores enviam e consumidores recebem/removem.'},{q:'A política normal de filas citada no material é:',opts:['FIFO.','Shortest path first.','Round robin BGP.','3f+1.'],a:0,why:'A política normal de queueing é first-in-first-out.'},{q:'Em tuple spaces, a operação que retorna e remove uma tupla é:',opts:['take.','read.','write.','GET.'],a:0,why:'write coloca tupla, read lê sem remover e take lê removendo do espaço de tuplas.'}]},
{code:'DS-08',module:'Modelos de falha',title:'Os dois generais não têm certeza',rank:'Fault Analyst',concepts:['two generals','message loss','common knowledge','acks'],brief:'Dois datacenters precisam confirmar uma transação: cobrar cartão e despachar produto. Mensagens podem se perder. Quantos ACKs bastam para certeza absoluta?',terminal:'shop -> payment: charge(card)\npayment -> shop: charged_ack\nshop -> logistics: dispatch\nproblem: lost messages prevent certainty',nodes:[['Loja',18,50,'🏬','live'],['Rede Insegura',50,50,'🌫️','bad'],['Pagamento',82,28,'💳','live'],['Logística',82,70,'📦','warn']],links:[[0,1,'bad'],[1,2,'bad'],[1,3]],packets:['red'],steps:[{q:'No problema dos dois generais, o ponto central é:',opts:['Nenhum número finito de mensagens garante certeza comum quando mensagens podem ser perdidas.','Uma única mensagem sempre garante acordo.','ACKs infinitos são práticos e resolvem tudo.','O problema só acontece com três ou mais generais maliciosos.'],a:0,why:'A sequência de ACKs aumenta confiança, mas não dá certeza absoluta com mensagens que podem ser interceptadas/perdidas.'},{q:'Na compra online, qual resultado é inconsistente?',opts:['Despachar sem cobrar ou cobrar sem despachar.','Não despachar e não cobrar.','Cobrar e despachar corretamente.','Consultar o catálogo.'],a:0,why:'O exemplo mostra que a loja deve despachar somente se pago e cobrar somente se despachado; quebrar um lado gera perda ou reclamação.'}]},
{code:'DS-09',module:'Bizantino',title:'Há traidores no cluster',rank:'BFT Analyst',concepts:['Byzantine','malicious nodes','3f+1','blockchain'],brief:'Um cluster de validação recebe mensagens contraditórias. Alguns nós podem mentir deliberadamente. O sistema precisa tolerar falhas bizantinas.',terminal:'fault model: Byzantine\nf malicious nodes tolerated -> need N >= 3f + 1\nexample: f=2 => N >= 7',nodes:[['N1',16,30,'🟢','live'],['N2',38,24,'🟢','live'],['N3',62,24,'🔴','bad'],['N4',84,30,'🟢','live'],['N5',23,72,'🔴','bad'],['N6',50,78,'🟢','live'],['N7',77,72,'🟢','live']],links:[[0,2],[2,4,'bad'],[1,5],[3,6],[4,5],[5,6],[0,5]],steps:[{q:'Para tolerar f nós maliciosos, o teorema apresentado exige:',opts:['3f + 1 nós no total.','2f nós no total.','f + 1 nós no total.','Exatamente 1 nó central.'],a:0,why:'O material afirma que são necessários 3f + 1 generais/nós para tolerar f maliciosos.'},{q:'Falha Byzantine significa que o nó pode:',opts:['Desviar arbitrariamente do algoritmo, mentir, coludir, travar ou agir maliciosamente.','Apenas parar para sempre de modo limpo.','Apenas perder memória e recuperar depois.','Nunca afetar segurança.'],a:0,why:'Byzantine/fail-arbitrary é o modelo em que o nó pode fazer qualquer comportamento, inclusive malicioso.'},{q:'Esse tipo de tolerância aparece muito em:',opts:['Blockchains e criptomoedas.','CSS responsivo.','Monitores CRT.','Apenas sistemas sem rede.'],a:0,why:'Os slides citam popularidade de BFT em blockchains e criptomoedas.'}]},
{code:'DS-10',module:'Links, nós e tempo',title:'Escolha suas suposições',rank:'System Modeler',concepts:['reliable links','fair-loss','crash-stop','crash-recovery','synchrony'],brief:'Você vai projetar um algoritmo. Antes, precisa escolher corretamente o modelo: comportamento da rede, dos nós e do tempo.',terminal:'network: reliable | fair-loss | arbitrary | partition\nnode: crash-stop | crash-recovery | Byzantine\ntiming: synchronous | partially synchronous | asynchronous',nodes:[['Algorithm',50,15,'📐','live'],['Network',22,55,'🌐','warn'],['Nodes',50,72,'🖥️','bad'],['Timing',78,55,'⏱️','warn']],links:[[0,1],[0,2],[0,3]],steps:[{q:'Fair-loss links permitem:',opts:['Perda, duplicação ou reordenação; com retry contínuo, a mensagem eventualmente chega.','Entrega perfeita sem reordenação.','Somente mensagens maliciosas modificadas.','Compartilhamento de memória entre datacenters.'],a:0,why:'Fair-loss admite perda/duplicação/reordenação, mas se repetir, eventualmente chega sob a suposição de falha finita.'},{q:'Crash-recovery significa:',opts:['O nó pode cair, perder estado em memória e depois voltar; dados em disco sobrevivem.','O nó nunca volta.','O nó mente deliberadamente.','A rede vira broadcast perfeito.'],a:0,why:'Crash-recovery permite queda e retomada posterior, mantendo estado persistido em disco.'},{q:'Sistema assíncrono significa:',opts:['Mensagens podem atrasar arbitrariamente e nós podem pausar sem garantias temporais.','Latência sempre menor que um limite conhecido.','Todos os nós executam na mesma velocidade.','Timeouts detectam falhas perfeitamente.'],a:0,why:'No modelo assíncrono não há garantias de tempo: atrasos e pausas podem ser arbitrários.'}]},
{code:'DS-11',module:'Alta disponibilidade',title:'Quatro noves ou multa',rank:'Reliability Engineer',concepts:['availability','SLO','SLA','SPOF','failure detector'],brief:'A empresa prometeu 99,99% de disponibilidade. Um único servidor virou SPOF. Você precisa entender uptime, SLO/SLA e detecção de falhas.',terminal:'availability target: 99.99%\nallowed downtime/year ~= 53 minutes\nSLO: 99.9% requests/day < 200ms\nSLA: contract + penalties',nodes:[['Load Balancer',50,20,'⚖️','live'],['API A',25,55,'⚙️','live'],['API B',50,65,'⚙️','warn'],['API C',75,55,'⚙️','live'],['DB Primary',50,88,'🗄️','bad']],links:[[0,1],[0,2],[0,3],[1,4],[2,4,'bad'],[3,4]],steps:[{q:'99,99% de disponibilidade corresponde aproximadamente a:',opts:['53 minutos de indisponibilidade por ano.','3,7 dias por ano.','8,8 horas por ano.','5,3 minutos por ano.'],a:0,why:'Quatro noves = 99,99% up ≈ 53 minutos de downtime por ano.'},{q:'SPOF é:',opts:['Um nó ou link cuja falha causa falha do sistema inteiro.','Um tipo de assinatura digital.','Um formato XML para SOAP.','Um tipo de tuple space.'],a:0,why:'Single Point of Failure é qualquer componente cuja falha derruba o sistema como um todo.'},{q:'Um detector de falhas por timeout tem o problema de:',opts:['Não distinguir perfeitamente nó crashado, nó lento, mensagem perdida ou mensagem atrasada.','Sempre detectar corretamente em sistemas assíncronos.','Transformar fair-loss em Byzantine.','Eliminar a necessidade de replicação.'],a:0,why:'Timeout não prova crash; pode ser atraso, perda ou lentidão. Detectores perfeitos exigem suposições fortes.'}]},
{code:'DS-12',module:'Middleware',title:'O tradutor invisível',rank:'Middleware Engineer',concepts:['middleware','CORBA','components','containers'],brief:'A Nebula usa Windows, Linux, Java, C++ e serviços legados. Middleware precisa esconder heterogeneidade e oferecer interoperabilidade e portabilidade.',terminal:'middleware layer:\n- higher-level programming abstraction\n- abstracts heterogeneity\n- interoperability + portability\nCORBA: IDL + ORB + CDR + remote refs',nodes:[['Client Java',15,35,'☕','live'],['ORB/Middleware',50,50,'🧵','live'],['C++ Object',84,35,'🔧','live'],['Container',50,78,'📦','warn']],links:[[0,1],[1,2],[1,3]],steps:[{q:'Função central do middleware no material:',opts:['Fornecer abstrações de alto nível e mascarar heterogeneidade da infraestrutura.','Substituir toda a rede física.','Impedir qualquer falha de nó.','Eliminar interfaces.'],a:0,why:'Middleware abstrai heterogeneidade, facilita interoperabilidade/portabilidade e oferece uma camada de programação de mais alto nível.'},{q:'CORBA permite que objetos distribuídos:',opts:['Sejam implementados em diferentes linguagens e comuniquem via ORB e IDL.','Usem apenas JavaScript local.','Evitem referências remotas.','Funcionem sem interface.'],a:0,why:'CORBA usa IDL independente de linguagem e o ORB ajuda a localizar, ativar e comunicar a requisição ao objeto.'},{q:'Componentes são especificados por contrato com:',opts:['Interfaces fornecidas e requeridas explicitamente.','Somente herança de classes.','Apenas arquivos HTML.','Ponteiros de memória.'],a:0,why:'Componentes têm contrato: provided interfaces e required interfaces, favorecendo composição sobre herança.'}]},
{code:'DS-13',module:'Web Services',title:'SOAP ou REST?',rank:'API Architect',concepts:['SOAP','REST','HTTP','XML','JSON','WSDL','UDDI'],brief:'Você vai expor a API de previsão do tempo. O time legado quer SOAP/WSDL; o app mobile quer REST/JSON. Escolha a tecnologia e entenda a diferença.',terminal:'REST:\nGET /weather/Lisbon -> {"temp":26}\nSOAP:\n<soap:Envelope><soap:Header/><soap:Body>...</soap:Body></soap:Envelope>\nWSDL describes operations',nodes:[['Mobile Client',14,50,'📱','live'],['HTTP',36,50,'🌐','live'],['REST API',60,30,'{}','live'],['SOAP Service',60,70,'XML','warn'],['UDDI/WSDL',84,70,'📜','live']],links:[[0,1],[1,2],[1,3],[3,4]],steps:[{q:'REST enfatiza principalmente:',opts:['Manipulação de recursos por URLs e operações HTTP como GET, PUT, DELETE e POST.','Uso obrigatório de WSDL e UDDI em todas as chamadas.','Apenas mensagens binárias não legíveis.','Comunicação sem HTTP.'],a:0,why:'REST usa URLs e operações HTTP para manipular recursos, com representações como XML ou JSON.'},{q:'SOAP usa tipicamente:',opts:['Mensagens XML em um Envelope com Header, Body e possível Fault.','Somente JSON via GET.','Tuple space com take.','DHT com GUID.'],a:0,why:'SOAP é baseado em mensagens XML; o envelope contém Header opcional, Body e Fault para erros.'},{q:'WSDL serve para:',opts:['Descrever a funcionalidade/interface de um web service.','Detectar falhas por timeout.','Escolher o nó mais próximo no Pastry.','Implementar FIFO.'],a:0,why:'WSDL é uma linguagem XML de descrição de interface/funcionalidade de web services.'}]},
{code:'DS-14',module:'P2P',title:'Encontre o arquivo sem servidor central',rank:'P2P Engineer',concepts:['Napster','DHT','GUID','Pastry','flooding','gossip'],brief:'Você precisa distribuir uma ISO da Nebula sem depender de um servidor central. Compare index centralizado, DHT, overlay routing e busca não estruturada.',terminal:'DHT API:\nput(GUID,value)\nvalue=get(GUID)\nremove(GUID)\nPastry: route in O(log N) with 128-bit GUIDs\nUnstructured: flooding | random walks | gossip',nodes:[['Peer A',16,28,'🧑‍💻','live'],['Peer B',40,18,'🧑‍💻','live'],['Peer C',68,22,'🧑‍💻','warn'],['Peer D',82,50,'🧑‍💻','live'],['Peer E',62,80,'🧑‍💻','bad'],['Peer F',30,75,'🧑‍💻','live']],links:[[0,1],[1,2],[2,3],[3,4,'bad'],[4,5],[5,0],[1,5],[2,4]],steps:[{q:'Em P2P, característica básica é:',opts:['Cada usuário contribui recursos e os nós têm capacidades/responsabilidades semelhantes.','Tudo depende de um servidor central obrigatório.','Não há necessidade de algoritmo de localização.','Nenhum nó pode falhar.'],a:0,why:'P2P elimina dependência de servidores gerenciados separadamente e cada peer contribui recursos.'},{q:'Em DHT, recursos são normalmente acessados por:',opts:['GUIDs, com o overlay escolhendo local, armazenando réplicas e oferecendo acesso.','Ponteiros físicos de RAM.','Somente endereço MAC.','ACKs infinitos.'],a:0,why:'DHT usa identificadores globais e a camada DHT escolhe onde armazenar/localizar, usando réplicas para disponibilidade.'},{q:'No Pastry com tabela estruturada, o número esperado de passos é aproximadamente:',opts:['O(log16 N).','O(N²).','Sempre 1.','3f+1.'],a:0,why:'Os slides indicam que Pastry com tabela roteia em O(log N), especificamente passos ≈ log16 N.'},{q:'Busca não estruturada por flooding tem como desvantagem:',opts:['Excesso de mensagens e impacto de escalabilidade.','Garantia absoluta com baixo overhead.','Obrigatoriedade de WSDL.','Detecção perfeita de crash.'],a:0,why:'Flooding é simples, mas pode gerar overhead grande e prejudicar escalabilidade.'}]},
{code:'DS-15',module:'Final',title:'Architect Mode: salve a Nebula',rank:'Distributed Architect',concepts:['arquitetura','comunicação','falhas','middleware','P2P','HA'],brief:'Fase final: combine tudo. Você precisa escolher arquitetura, comunicação, modelo de falhas, middleware e disponibilidade para uma plataforma global.',terminal:'objectives:\navailability >= 99.99%\nlatency < 200ms\nno critical data loss\nhandle: partition + crash + malicious node + overload',nodes:[['Users',10,50,'👥','live'],['Proxy/LB',28,50,'⚖️','live'],['API Cluster',48,35,'⚙️','live'],['Queue',48,66,'📥','live'],['DB Replicas',72,35,'🗄️','warn'],['P2P CDN',72,66,'🕸️','live'],['Monitor',90,50,'📈','live']],links:[[0,1],[1,2],[1,3],[2,4],[3,4],[2,5],[4,6],[5,6]],steps:[{q:'Para evitar SPOF e atingir alta disponibilidade, a melhor decisão inicial é:',opts:['Redundância: múltiplas réplicas, balanceador, monitoramento e failover.','Um único servidor mais forte.','Remover todos os timeouts.','Usar apenas chamadas locais.'],a:0,why:'Alta disponibilidade exige eliminar pontos únicos de falha por redundância, replicação, monitoramento e failover.'},{q:'Para absorver picos de pedidos sem derrubar consumidores lentos:',opts:['Usar message queue entre produtores e consumidores.','Remover a camada de aplicação.','Trocar TCP por HTML.','Usar ACKs infinitos.'],a:0,why:'Filas desacoplam produtores/consumidores e ajudam a absorver picos de carga.'},{q:'Para distribuir arquivos em larga escala com localização descentralizada:',opts:['P2P/DHT com GUIDs e réplicas.','Somente proxy central único.','RPC síncrono para cada byte.','WSDL obrigatório.'],a:0,why:'P2P com DHT/overlay usa GUIDs, réplicas e roteamento para localização distribuída.'},{q:'Se existem nós maliciosos, o modelo de falha adequado é:',opts:['Byzantine/fail-arbitrary.','Crash-stop apenas.','Synchronous only.','Access transparency.'],a:0,why:'Nós maliciosos exigem modelo Byzantine, pois podem mentir ou desviar do algoritmo.'}]},
{code:'DS-16',module:'Integração jogável',title:'Mini Sistema Distribuído: conecte tudo',rank:'Lead Distributed Architect',concepts:['client-server','proxy','REST','RPC/RMI','queue','pub-sub','replicação','failure detector','SLO/SLA','P2P/DHT','Byzantine'],brief:'Agora você vai condensar todos os conceitos em um mini sistema distribuído jogável. Para cada incidente, escolha o bloco de código/arquitetura correto e veja a NebulaShop ficar mais resiliente.',terminal:'mini-system: NebulaShop\nflow: Client -> Proxy/LB -> API Cluster -> Queue/Broker -> Workers -> DB Replicas -> Monitoring -> P2P CDN\nincidents: overload + lost messages + crash + partition + malicious node\ngoal: connect concepts with code choices',nodes:[['Client',8,50,'👤','live'],['Proxy/LB',24,50,'⚖️','live'],['API A',42,32,'⚙️','live'],['API B',42,68,'⚙️','live'],['Broker/Queue',60,50,'📬','live'],['DB Replicas',78,32,'🗄️','warn'],['P2P CDN',78,68,'🕸️','live'],['Monitor',92,50,'📈','live']],links:[[0,1],[1,2],[1,3],[2,4],[3,4],[4,5],[4,6],[5,7],[6,7]],packets:['cyan','amber','red'],steps:[{q:'No mini sistema, qual escolha conecta melhor transparência de localização, disponibilidade e escalabilidade na entrada?',opts:['Colocar Proxy/Load Balancer na frente do cluster de APIs.','Mandar todos os clientes direto para uma única API fixa.','Remover monitoramento para reduzir ruído.','Usar apenas um banco local dentro do navegador.'],a:0,why:'O proxy/load balancer esconde localização, distribui carga, permite failover e ajuda a reduzir SPOF.'},{q:'Quando os pedidos chegam mais rápido que os workers processam, qual bloco de código/arquitetura deve ser escolhido?',opts:['Producer -> Queue -> Consumer, com mensagens persistentes e processamento assíncrono.','RPC síncrono para cada etapa, sem buffer.','Excluir pedidos antigos para preservar latência.','Enviar a mesma mensagem para todos os clientes via broadcast.'],a:0,why:'Filas dão desacoplamento temporal, absorvem rajadas e protegem consumidores lentos.'},{q:'Para arquivos estáticos grandes e localização descentralizada, qual componente fecha melhor o desenho?',opts:['P2P/DHT com GUID, get/put e réplicas.','SOAP Fault no banco de dados.','Dois generais com ACK infinito.','Um único servidor FTP como ponto central.'],a:0,why:'DHT/P2P usa GUIDs, réplicas e overlay para localizar recursos sem depender de servidor central único.'},{q:'Se uma API para de responder, mas talvez seja apenas latência, qual conceito o sistema precisa aplicar?',opts:['Failure detector por heartbeat/timeout, aceitando suspeitas temporárias em sistema parcialmente síncrono.','Detecção perfeita em rede assíncrona sem erro.','Remover todos os timeouts.','Assumir Byzantine sempre que houver atraso.'],a:0,why:'Timeouts podem confundir crash, atraso e perda de mensagem; por isso o detector é uma suspeita e pode se tornar eventualmente correto.'},{q:'Se alguns nós podem mentir ou mandar respostas conflitantes, qual modelo entra no projeto?',opts:['Byzantine/fail-arbitrary e consenso com quórum suficiente.','Crash-stop simples e sem validação.','Access transparency.','Tuple space apenas.'],a:0,why:'Nós maliciosos exigem modelo bizantino; tolerar f falhas bizantinas requer raciocínio de quórum, como 3f+1 no modelo clássico.'}]}
];

let state={mission:0,step:0,score:0,answered:false,done:{},streak:0};
const $=s=>document.querySelector(s);
const app=document.getElementById('app');
const totalSteps=()=>MISSIONS.reduce((a,m)=>a+m.steps.length,0);
const completedSteps=()=>Object.values(state.done).reduce((a,v)=>a+v,0);
function save(){localStorage.setItem('nebula-ds-state',JSON.stringify(state));}
function load(){try{const s=JSON.parse(localStorage.getItem('nebula-ds-state')||'null'); if(s&&typeof s==='object')state={...state,...s,answered:false};}catch(e){}}
function metric(){const pct=Math.round(completedSteps()/totalSteps()*100);return {pct,uptime:Math.min(99.99,(96+pct/25)).toFixed(2),lat:Math.max(85,260-pct*1.4).toFixed(0),cons:Math.min(100,45+pct).toFixed(0)};}
function toast(msg){let t=document.createElement('div');t.className='toast';t.textContent=msg;document.body.appendChild(t);requestAnimationFrame(()=>t.classList.add('show'));setTimeout(()=>{t.classList.remove('show');setTimeout(()=>t.remove(),400)},1800)}
function renderShell(){const m=metric();app.innerHTML=`
<nav class="topbar"><a class="brand" href="../../pages/jogos.html"><span class="brand-badge">🌐</span><span>Nebula DS Academy</span></a><div class="nav-actions"><button class="btn" id="reset">Reiniciar</button><a class="btn" href="../../pages/sistemas-distribuidos.html">Módulo teórico</a><a class="btn primary" href="../../pages/jogos.html">Jogos</a></div></nav>
<section class="hero"><div><div class="eyebrow">Sistemas Distribuídos · IPB</div><h1>Salve a nuvem distribuída.</h1><p>Um jogo baseado nos PDFs de introdução, comunicação, modelos e middleware. Resolva incidentes, veja mensagens atravessarem nós e aprenda arquitetura, falhas, IPC, pub-sub, filas, web services e P2P.</p><div class="stat-row"><div class="stat"><strong>${m.pct}%</strong><span>currículo</span></div><div class="stat"><strong>${m.uptime}%</strong><span>uptime simulado</span></div><div class="stat"><strong>${m.lat}ms</strong><span>latência</span></div><div class="stat"><strong>${state.score}</strong><span>pontos</span></div></div><button class="btn primary" id="continue">Continuar missão</button></div><div class="hero-card"><div class="mini-map"><div class="node live"><span class="pulse"></span><b>Datacenter EU</b><span>API + Queue</span></div><div class="node warn"><span class="pulse"></span><b>Datacenter US</b><span>fair-loss link</span></div><div class="node live"><span class="pulse"></span><b>Edge CDN</b><span>P2P/DHT</span></div><div class="node bad"><span class="pulse"></span><b>Fault Zone</b><span>partition</span></div><div class="node live"><span class="pulse"></span><b>Middleware</b><span>REST/RMI</span></div><div class="node live"><span class="pulse"></span><b>Monitoring</b><span>SLO/SLA</span></div></div></div></section>
<section class="layout"><aside class="side"><h2>Currículo jogável</h2><div class="mission-list">${MISSIONS.map((x,i)=>`<button class="mission-tab ${i===state.mission?'active':''} ${state.done[x.code]>=x.steps.length?'done':''}" data-m="${i}"><div class="top"><span class="code">${x.code}</span><span class="tag">${x.module}</span></div><b>${x.title}</b><small>${x.concepts.join(' · ')}</small></button>`).join('')}</div></aside><main class="main" id="main"></main></section>`;
$('#reset').onclick=()=>{localStorage.removeItem('nebula-ds-state');state={mission:0,step:0,score:0,answered:false,done:{},streak:0};renderShell();renderMission();};
$('#continue').onclick=()=>document.getElementById('main').scrollIntoView({behavior:'smooth',block:'start'});
document.querySelectorAll('.mission-tab').forEach(b=>b.onclick=()=>{state.mission=+b.dataset.m;state.step=Math.min(state.done[MISSIONS[state.mission].code]||0,MISSIONS[state.mission].steps.length-1);state.answered=false;save();renderShell();renderMission();});
}
function drawVisual(m){const nodes=m.nodes.map((n,i)=>`<div class="ds-node ${n[4]||'good'}" style="left:${n[1]}%;top:${n[2]}%"><div class="emoji">${n[3]}</div><b>${n[0]}</b><small>${m.concepts[i%m.concepts.length]}</small></div>`).join('');
const links=(m.links||[]).map(l=>lineFor(m.nodes[l[0]],m.nodes[l[1]],l[2])).join('');
const packets=(m.links||[]).slice(0,5).map((l,i)=>packetFor(m.nodes[l[0]],m.nodes[l[1]],(m.packets&&m.packets[i%m.packets.length])||'cyan')).join('');
return `<div class="canvas">${links}${packets}${nodes}</div>`;}
function lineFor(a,b,bad){const x1=a[1],y1=a[2],x2=b[1],y2=b[2];const dx=x2-x1,dy=y2-y1;const len=Math.sqrt(dx*dx+dy*dy);const ang=Math.atan2(dy,dx)*180/Math.PI;return `<div class="link ${bad==='bad'?'bad':''}" style="left:${x1}%;top:${y1}%;width:${len}%;transform:rotate(${ang}deg)"></div>`}
function packetFor(a,b,color){const x1=a[1],y1=a[2],x2=b[1],y2=b[2];return `<div class="packet ${color==='red'?'red':color==='amber'?'amber':''}" style="offset-path:path('M ${x1} ${y1} L ${x2} ${y2}');left:0;top:0"></div>`}
function renderMission(){const m=MISSIONS[state.mission];const st=m.steps[state.step]||m.steps[0];const doneIn=state.done[m.code]||0;const mm=metric();const main=document.getElementById('main');main.innerHTML=`<article class="panel"><header class="mission-head"><div><span class="eyebrow">${m.code} · ${m.module} · ${m.rank}</span><h2>${m.title}</h2><p>${m.brief}</p></div><div class="scorebox"><span class="pill ok">${doneIn}/${m.steps.length} etapas</span><span class="pill">Consistência ${mm.cons}%</span></div></header><section class="sim"><div class="visual">${drawVisual(m)}</div><div class="info"><div class="brief"><b>Conceitos:</b> ${m.concepts.join(', ')}.<br><br>${scenarioLine(m.code)}</div><div class="terminal">${highlight(m.terminal)}</div></div></section><section class="challenge"><div class="progress"><i style="width:${((state.step)/m.steps.length)*100}%"></i></div><div class="question">${st.q}</div><div class="options">${st.opts.map((o,i)=>`<button class="opt" data-i="${i}">${o}</button>`).join('')}</div><div class="feedback" id="feedback"></div><div class="actions"><button class="btn" id="prev">← Missão anterior</button><button class="btn primary" id="next" style="display:none">Próxima etapa →</button></div></section>${m.code==='DS-16'?renderIntegrationBuilder():''}${renderSystemOverview(m)}${renderJavaLab(m)}<section class="curriculum"><div class="cur-card"><b>Introdução</b><span>definição, motivações, desafios, transparência e QoS.</span></div><div class="cur-card"><b>Comunicação</b><span>OSI/TCP/IP, sockets, invocação remota, indireção, filas e espaços.</span></div><div class="cur-card"><b>Modelos</b><span>dois generais, bizantino, links, nós, timing, disponibilidade.</span></div><div class="cur-card"><b>Arquitetura</b><span>middleware, CORBA, componentes, web services e P2P.</span></div></section></article>`;
main.querySelectorAll('.opt').forEach(btn=>btn.onclick=()=>answer(+btn.dataset.i));
$('#prev').onclick=()=>{if(state.mission>0){state.mission--;state.step=0;state.answered=false;save();renderShell();renderMission();}};
$('#next').onclick=advance;
setupJavaLab(m);
if(m.code==='DS-16')setupIntegrationBuilder();
}
const JAVA_LABS={
'DS-01':{title:'Modelar nós e mensagens',goal:'Crie uma mensagem entre componentes independentes.',starter:'class Message {\n  String from, to, body;\n  Message(String from, String to, String body){\n    this.from = from; this.to = to; this.body = body;\n  }\n}\n\nclass Node {\n  String name;\n  Node(String name){ this.name = name; }\n  void send(Node target, String body){\n    Message msg = new Message(this.name, target.name, body);\n    System.out.println(msg.from + " -> " + msg.to + ": " + msg.body);\n  }\n}',checks:['class Message','class Node','send','System.out.println'],output:'API-EU -> API-US: health-check'},
'DS-02':{title:'Location transparency com proxy',goal:'Use um proxy para esconder o datacenter real do serviço.',starter:'interface CatalogService {\n  String getProduct(String id);\n}\n\nclass CatalogProxy implements CatalogService {\n  private CatalogService current;\n  CatalogProxy(CatalogService current){ this.current = current; }\n  public String getProduct(String id){\n    return current.getProduct(id);\n  }\n}',checks:['interface CatalogService','class CatalogProxy','implements CatalogService','getProduct'],output:'Cliente chamou /catalog sem saber se o serviço estava na EU ou US.'},
'DS-03':{title:'Arquitetura three-tier',goal:'Separe cliente, lógica de aplicação e banco.',starter:'class Client { }\nclass ApplicationService { }\nclass DatabaseManager { }\n\nclass EcommerceSystem {\n  Client client = new Client();\n  ApplicationService app = new ApplicationService();\n  DatabaseManager db = new DatabaseManager();\n}',checks:['class Client','class ApplicationService','class DatabaseManager','EcommerceSystem'],output:'Camadas conectadas: UI -> Application Logic -> Database.'},
'DS-04':{title:'Socket TCP em Java',goal:'Mostre a sequência conceitual do socket TCP.',starter:'import java.net.Socket;\nimport java.io.*;\n\nclass ChatClient {\n  void connect() throws Exception {\n    Socket socket = new Socket("nebula.local", 8080);\n    PrintWriter out = new PrintWriter(socket.getOutputStream(), true);\n    BufferedReader in = new BufferedReader(new InputStreamReader(socket.getInputStream()));\n    out.println("HELLO");\n    socket.close();\n  }\n}',checks:['Socket','getOutputStream','getInputStream','close'],output:'SYN -> SYN-ACK -> ACK -> HELLO -> close.'},
'DS-05':{title:'RMI/RPC com exceção remota',goal:'Modele uma chamada remota que pode falhar.',starter:'interface RemoteAccount {\n  void deposit(double amount) throws RemoteException;\n}\n\nclass RemoteException extends Exception {\n  RemoteException(String msg){ super(msg); }\n}\n\nclass Client {\n  void pay(RemoteAccount account) throws RemoteException {\n    account.deposit(100.0);\n  }\n}',checks:['interface RemoteAccount','throws RemoteException','deposit','Client'],output:'Chamada remota enviada; cliente deve validar timeout/falha.'},
'DS-06':{title:'Publish-subscribe',goal:'Crie um EventBus simples para desacoplar publisher e subscribers.',starter:'import java.util.*;\n\ninterface Subscriber { void notify(String event); }\n\nclass EventBus {\n  List<Subscriber> subscribers = new ArrayList<>();\n  void subscribe(Subscriber s){ subscribers.add(s); }\n  void publish(String event){\n    for(Subscriber s: subscribers) s.notify(event);\n  }\n}',checks:['interface Subscriber','class EventBus','subscribe','publish'],output:'Evento publicado no broker e entregue aos assinantes.'},
'DS-07':{title:'Message Queue FIFO',goal:'Use uma fila para absorver rajadas de pedidos.',starter:'import java.util.*;\n\nclass MessageQueue {\n  Queue<String> queue = new LinkedList<>();\n  void send(String msg){ queue.offer(msg); }\n  String receive(){ return queue.poll(); }\n}',checks:['Queue','LinkedList','send','receive'],output:'Pedido-1, Pedido-2, Pedido-3 processados em FIFO.'},
'DS-08':{title:'ACK com incerteza',goal:'Modele retry/ack sem prometer certeza absoluta.',starter:'class TwoGeneralsClient {\n  boolean sendWithAck(String message, int retries){\n    for(int i=0;i<retries;i++){\n      System.out.println("send: " + message);\n      // se o ACK não chega, repetimos; ainda assim não há certeza absoluta\n    }\n    return false;\n  }\n}',checks:['sendWithAck','retries','ACK','return false'],output:'Confiança aumenta com retries, mas certeza absoluta não é atingida.'},
'DS-09':{title:'Byzantine vote',goal:'Calcule maioria e lembre a regra 3f+1.',starter:'import java.util.*;\n\nclass ByzantineVote {\n  String majority(List<String> votes){\n    long attack = votes.stream().filter(v -> v.equals("ATTACK")).count();\n    return attack > votes.size()/2 ? "ATTACK" : "RETREAT";\n  }\n}',checks:['majority','votes','ATTACK','votes.size()'],output:'Maioria honesta decide; para tolerar f maliciosos, use N >= 3f + 1.'},
'DS-10':{title:'Failure detector por timeout',goal:'Mostre que timeout pode confundir crash com latência.',starter:'class FailureDetector {\n  boolean suspect(long lastHeartbeatMs, long nowMs, long timeoutMs){\n    return nowMs - lastHeartbeatMs > timeoutMs;\n  }\n}',checks:['FailureDetector','suspect','timeoutMs','return'],output:'Nó suspeito: pode estar crashado, lento ou com mensagem perdida.'},
'DS-11':{title:'Calcular disponibilidade',goal:'Calcule uptime anual aproximado a partir do downtime.',starter:'class Availability {\n  double availability(double downtimeMinutesPerYear){\n    double year = 365.0 * 24 * 60;\n    return 100.0 * (year - downtimeMinutesPerYear) / year;\n  }\n}',checks:['availability','downtimeMinutesPerYear','365.0','return'],output:'53 minutos/ano ≈ 99.99% de disponibilidade.'},
'DS-12':{title:'Middleware como camada de abstração',goal:'Use uma interface para esconder heterogeneidade.',starter:'interface PaymentGateway {\n  boolean charge(double amount);\n}\n\nclass MiddlewareAdapter implements PaymentGateway {\n  public boolean charge(double amount){\n    System.out.println("Normaliza protocolo e formato da mensagem");\n    return true;\n  }\n}',checks:['interface PaymentGateway','MiddlewareAdapter','implements PaymentGateway','charge'],output:'Cliente fala com uma abstração; SO/protocolo/formato ficam escondidos.'},
'DS-13':{title:'REST resource handler',goal:'Modele operações HTTP sobre recursos.',starter:'class WeatherResource {\n  String get(String city){ return "{\\\"temp\\\":26}"; }\n  String post(String body){ return "created"; }\n  String delete(String id){ return "deleted"; }\n}',checks:['get','post','delete','WeatherResource'],output:'GET /weather/Lisbon -> JSON; recurso manipulado por URL.'},
'DS-14':{title:'DHT put/get',goal:'Modele uma DHT mínima com GUID.',starter:'import java.util.*;\n\nclass DHT {\n  Map<String,String> store = new HashMap<>();\n  void put(String guid, String value){ store.put(guid, value); }\n  String get(String guid){ return store.get(guid); }\n  void remove(String guid){ store.remove(guid); }\n}',checks:['Map','put','get','remove'],output:'GUID localizado no overlay; réplicas aumentariam disponibilidade.'},
'DS-15':{title:'Sistema distribuído integrado',goal:'Monte uma visão geral com API, fila, banco, cache, monitoramento e P2P.',starter:'class DistributedSystem {\n  String[] nodes = {"LoadBalancer", "ApiCluster", "Queue", "DatabaseReplica", "Cache", "P2POverlay", "Monitoring"};\n  void describe(){\n    for(String n: nodes) System.out.println(n);\n  }\n}',checks:['DistributedSystem','LoadBalancer','Queue','DatabaseReplica','Monitoring'],output:'Arquitetura integrada pronta para injetar falhas e observar métricas.'},
'DS-16':{title:'Mini sistema distribuído completo',goal:'Condense os conceitos em classes Java conectando proxy, API, fila, worker, réplicas, detector de falhas e DHT.',starter:'import java.util.*;\n\nclass MiniDistributedSystem {\n  LoadBalancer lb = new LoadBalancer();\n  MessageQueue queue = new MessageQueue();\n  FailureDetector detector = new FailureDetector();\n  DHT cdn = new DHT();\n\n  void handleOrder(String order){\n    String api = lb.route();\n    queue.send(order);\n    System.out.println("Roteado para " + api + " e colocado na fila");\n  }\n}\n\nclass LoadBalancer {\n  String[] apis = {"api-a", "api-b"};\n  int next = 0;\n  String route(){ return apis[(next++) % apis.length]; }\n}\n\nclass MessageQueue {\n  Queue<String> q = new LinkedList<>();\n  void send(String msg){ q.add(msg); }\n  String receive(){ return q.poll(); }\n}\n\nclass FailureDetector {\n  boolean suspect(long lastHeartbeat, long now, long timeout){\n    return now - lastHeartbeat > timeout;\n  }\n}\n\nclass DHT {\n  Map<String,String> data = new HashMap<>();\n  void put(String guid, String value){ data.put(guid, value); }\n  String get(String guid){ return data.get(guid); }\n}',checks:['MiniDistributedSystem','LoadBalancer','MessageQueue','FailureDetector','DHT','handleOrder','route','send','receive','suspect','put','get'],output:'Mini sistema conectado: entrada via LB, pedidos na fila, workers consumindo, suspeita por heartbeat/timeout e arquivos no overlay DHT.'}
};
function currentLab(m){return JAVA_LABS[m.code]||JAVA_LABS['DS-15'];}
function renderJavaLab(m){const lab=currentLab(m);const saved=localStorage.getItem('nebula-java-'+m.code);const code=(saved||lab.starter).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');return `<section class="java-lab"><div class="lab-head"><div><span class="eyebrow">Java Lab · prática</span><h3>${lab.title}</h3><p>${lab.goal}</p></div><span class="pill">validação local</span></div><div class="lab-grid"><div><label class="lab-label" for="java-editor">Editor Java</label><textarea id="java-editor" spellcheck="false">${code}</textarea><div class="lab-actions"><button class="btn primary" id="run-java">Executar simulação</button><button class="btn" id="reset-java">Restaurar código</button></div></div><div class="lab-output"><b>Console simulado</b><pre id="java-output">Clique em Executar simulação. O navegador valida padrões de código e mostra o comportamento distribuído esperado.</pre><div class="lab-checks">${lab.checks.map(c=>`<span data-check="${c.replace(/"/g,'&quot;')}">○ ${c}</span>`).join('')}</div></div></div></section>`;}
function setupJavaLab(m){const ed=$('#java-editor');if(!ed)return;const lab=currentLab(m);const key='nebula-java-'+m.code;ed.addEventListener('input',()=>localStorage.setItem(key,ed.value));$('#reset-java').onclick=()=>{ed.value=lab.starter;localStorage.setItem(key,ed.value);$('#java-output').textContent='Código restaurado. Execute novamente.';updateLabChecks(lab,ed.value);};$('#run-java').onclick=()=>{const code=ed.value;localStorage.setItem(key,code);const missing=lab.checks.filter(c=>!code.includes(c));updateLabChecks(lab,code);if(missing.length){$('#java-output').textContent='⚠ Ainda falta no código: '+missing.join(', ')+'\n\nDica: complete o padrão da missão antes de avançar para uma implementação real em Java.';toast('Java Lab: complete os requisitos');}else{$('#java-output').textContent='✅ Compilação conceitual OK\n> javac Mission.java\n> java Mission\n'+lab.output+'\n\nObservação: esta é uma simulação no navegador. Para executar de verdade, copie o código para o VS Code/IntelliJ com JDK.';state.score+=5;save();toast('Java Lab concluído +5');}};updateLabChecks(lab,ed.value);}
function updateLabChecks(lab,code){document.querySelectorAll('.lab-checks span').forEach(s=>{const c=s.dataset.check;s.textContent=(code.includes(c)?'✓ ':'○ ')+c;s.classList.toggle('done',code.includes(c));});}

const INTEGRATION_STAGES=[
{key:'entry',title:'1. Entrada e transparência',incident:'Clientes não podem conhecer a localização real das APIs. Uma API pode cair sem derrubar o serviço.',correct:'lb',choices:{lb:{label:'Proxy / Load Balancer',code:'class LoadBalancer {\n  String[] apis = {"api-a", "api-b"};\n  int next = 0;\n  String route(){ return apis[(next++) % apis.length]; }\n}',effect:'✓ Location transparency + failover + menos SPOF'},direct:{label:'Cliente direto para API única',code:'String api = "api-a";\nclient.call(api + "/orders");',effect:'✗ API única vira SPOF e expõe localização'},broadcast:{label:'Broadcast para todas as APIs',code:'for(Api api: apis) api.process(order);',effect:'✗ Duplica pedidos e cria inconsistência'}}},
{key:'load',title:'2. Pico de carga',incident:'Black Friday: produtores geram pedidos mais rápido do que consumidores processam.',correct:'queue',choices:{queue:{label:'Message Queue FIFO',code:'class MessageQueue {\n  Queue<String> q = new LinkedList<>();\n  void send(String m){ q.add(m); }\n  String receive(){ return q.poll(); }\n}',effect:'✓ Time uncoupling + absorção de rajadas'},sync:{label:'RPC síncrono em cadeia',code:'payment.charge(order);\nstock.reserve(order);\nshipping.dispatch(order);',effect:'✗ Um serviço lento trava a cadeia inteira'},drop:{label:'Descartar excesso',code:'if(queueSize > 100) return "drop";',effect:'✗ Perda de dados crítica'}}},
{key:'events',title:'3. Eventos e observabilidade',incident:'Marketing, antifraude e monitoramento precisam receber o mesmo evento sem acoplamento direto.',correct:'pubsub',choices:{pubsub:{label:'Publish-Subscribe',code:'broker.subscribe("orders", fraud);\nbroker.subscribe("orders", monitoring);\nbroker.publish("orders", event);',effect:'✓ Space uncoupling + one-to-many'},loop:{label:'Chamar cada serviço manualmente',code:'fraud.notify(event);\nmarketing.notify(event);\nmonitoring.notify(event);',effect:'✗ Acoplamento forte e difícil evolução'},file:{label:'Arquivo compartilhado local',code:'Files.writeString(Path.of("orders.log"), event);',effect:'✗ Não resolve distribuição nem notificação'}}},
{key:'data',title:'4. Dados e disponibilidade',incident:'O banco primário caiu. O sistema precisa continuar operando e reduzir perda crítica.',correct:'replica',choices:{replica:{label:'Réplicas + failover',code:'class ReplicaSet {\n  List<String> replicas = List.of("db-a", "db-b", "db-c");\n  String primary(){ return replicas.get(0); }\n  String failover(){ return replicas.get(1); }\n}',effect:'✓ Redundância + recuperação'},single:{label:'Banco único',code:'String database = "db-primary";',effect:'✗ SPOF evidente'},memory:{label:'Guardar só em memória da API',code:'Map<String,String> orders = new HashMap<>();',effect:'✗ Crash-recovery perde estado em memória'}}},
{key:'faults',title:'5. Falhas e timeouts',incident:'Uma API não responde. Pode ser crash, atraso ou mensagem perdida.',correct:'detector',choices:{detector:{label:'Failure detector por heartbeat',code:'boolean suspect(long last, long now, long timeout){\n  return now - last > timeout;\n}',effect:'✓ Suspeita operacional, com possibilidade de falso positivo'},perfect:{label:'Detector perfeito em rede assíncrona',code:'boolean crashed(Node n){ return !n.replyNow(); }',effect:'✗ Confunde atraso com crash'},ignore:{label:'Ignorar falhas',code:'while(true) call(api);',effect:'✗ Pode bloquear indefinidamente'}}},
{key:'cdn',title:'6. Arquivos globais',incident:'Arquivos grandes precisam ser encontrados sem servidor central e com peers voláteis.',correct:'dht',choices:{dht:{label:'P2P / DHT por GUID',code:'dht.put(guid, "video.mp4");\nString file = dht.get(guid);',effect:'✓ Localização descentralizada + réplicas'},central:{label:'Servidor central único',code:'String file = centralServer.download(name);',effect:'✗ Gargalo e SPOF'},flood:{label:'Flooding sem limite',code:'for(Peer p: neighbours) p.forward(request);',effect:'△ Funciona, mas pode gerar overhead excessivo'}}},
{key:'security',title:'7. Nós maliciosos',incident:'Alguns nós enviam respostas conflitantes para fraudar pedidos.',correct:'byzantine',choices:{byzantine:{label:'Quórum / modelo Byzantine',code:'int f = 1;\nint requiredNodes = 3 * f + 1;\nboolean decided = votesFor(value) >= 2 * f + 1;',effect:'✓ Tolera comportamento arbitrário dentro do limite'},crash:{label:'Crash-stop simples',code:'if(!node.responds()) markCrashed(node);',effect:'✗ Não trata nó mentindo'},trust:{label:'Confiar no primeiro nó',code:'return responses.get(0);',effect:'✗ Vulnerável a traidor'}}}
];
function renderIntegrationBuilder(){return `<section class="integration-game"><div class="integration-head"><div><span class="eyebrow">DS-16 · Mini sistema jogável</span><h3>Escolha o código certo para cada incidente</h3><p>Monte a NebulaShop conectando comunicação, arquitetura, indireção, falhas, disponibilidade, middleware e P2P.</p></div><div class="integration-score"><b id="ig-score">0/${INTEGRATION_STAGES.length}</b><span>blocos corretos</span></div></div><div class="system-board"><div class="sys-node" data-k="entry">Cliente → Proxy/LB</div><div class="sys-node" data-k="load">API → Queue</div><div class="sys-node" data-k="events">Broker Pub/Sub</div><div class="sys-node" data-k="data">DB Replicas</div><div class="sys-node" data-k="faults">Failure Detector</div><div class="sys-node" data-k="cdn">P2P/DHT</div><div class="sys-node" data-k="security">Byzantine Quorum</div></div><div id="integration-stage"></div><div class="integration-console"><b>Console do mini sistema</b><pre id="ig-console">Escolha um bloco de código para iniciar a simulação.</pre></div></section>`;}
function setupIntegrationBuilder(){let idx=+(localStorage.getItem('nebula-ds16-stage')||0);let solved=JSON.parse(localStorage.getItem('nebula-ds16-solved')||'{}');const render=()=>{const stage=INTEGRATION_STAGES[Math.min(idx,INTEGRATION_STAGES.length-1)];const count=Object.keys(solved).length;const score=document.getElementById('ig-score');if(score)score.textContent=count+'/'+INTEGRATION_STAGES.length;document.querySelectorAll('.sys-node').forEach(n=>n.classList.toggle('done',!!solved[n.dataset.k]));const host=document.getElementById('integration-stage');if(!host)return;if(count===INTEGRATION_STAGES.length){host.innerHTML=`<div class="stage-card complete"><h4>✅ Mini sistema conectado</h4><p>Você combinou Proxy/LB, filas, pub-sub, réplicas, detector de falhas, DHT e quórum bizantino. Agora a arquitetura tem uma visão prática dos conceitos centrais da disciplina.</p><button class="btn" id="ig-reset">Reiniciar DS-16</button></div>`;document.getElementById('ig-console').textContent='NebulaShop online\n✓ entrada resiliente\n✓ pedidos desacoplados por fila\n✓ eventos entregues por pub-sub\n✓ dados replicados\n✓ falhas monitoradas\n✓ arquivos localizados por DHT\n✓ decisões protegidas por quórum';document.getElementById('ig-reset').onclick=()=>{localStorage.removeItem('nebula-ds16-stage');localStorage.removeItem('nebula-ds16-solved');setupIntegrationBuilder();};return;}if(solved[stage.key]){idx++;localStorage.setItem('nebula-ds16-stage',idx);render();return;}host.innerHTML=`<div class="stage-card"><div class="stage-meta"><span class="pill ok">${stage.title}</span><span class="pill">incidente</span></div><h4>${stage.incident}</h4><div class="code-choice-grid">${Object.entries(stage.choices).map(([k,c])=>`<button class="code-choice" data-choice="${k}"><b>${c.label}</b><pre>${c.code.replace(/</g,'&lt;').replace(/>/g,'&gt;')}</pre><small>${c.effect}</small></button>`).join('')}</div></div>`;document.querySelectorAll('.code-choice').forEach(b=>b.onclick=()=>{const choice=b.dataset.choice;document.querySelectorAll('.code-choice').forEach(x=>x.disabled=true);if(choice===stage.correct){b.classList.add('correct');solved[stage.key]=choice;idx++;state.score+=12;save();localStorage.setItem('nebula-ds16-stage',idx);localStorage.setItem('nebula-ds16-solved',JSON.stringify(solved));document.getElementById('ig-console').textContent='✅ '+stage.title+'\n'+stage.choices[choice].effect+'\n\nCódigo aplicado:\n'+stage.choices[choice].code;toast('DS-16: bloco correto aplicado');setTimeout(render,900);}else{b.classList.add('wrong');document.getElementById('ig-console').textContent='⚠ Bloco inadequado para este incidente.\n'+stage.choices[choice].effect+'\n\nTente conectar o conceito certo ao problema apresentado.';toast('Escolha outro bloco');setTimeout(()=>{document.querySelectorAll('.code-choice').forEach(x=>{x.disabled=false;x.classList.remove('wrong')})},700);}});};render();}

function renderSystemOverview(m){const rows=[['Cliente','faz requisições HTTP/RPC e percebe transparência'],['Load Balancer / Proxy','esconde localização, distribui carga e evita SPOF'],['API Cluster','processa lógica; nós podem falhar independentemente'],['Broker / Queue','desacopla produtores e consumidores no tempo e no espaço'],['Database Replicas','replicação, consistência e recuperação de falhas'],['Monitoring','SLO, SLA, detector de falhas e métricas'],['P2P/DHT','localização por GUID e overlay routing']];return `<section class="overview"><div class="overview-head"><div><span class="eyebrow">Visão geral aplicada</span><h3>Arquitetura Nebula Cloud</h3><p>Veja onde o conceito desta missão entra em um sistema distribuído real.</p></div><span class="pill ok">${m.code}</span></div><div class="overview-flow"><div class="ov-node client">Cliente</div><div class="ov-arrow">→</div><div class="ov-node">Proxy/LB</div><div class="ov-arrow">→</div><div class="ov-node">API Cluster</div><div class="ov-arrow">→</div><div class="ov-node">Queue/Broker</div><div class="ov-arrow">→</div><div class="ov-node">DB Replicas</div><div class="ov-node sidecar">Monitoring</div><div class="ov-node p2p">P2P/DHT</div></div><div class="overview-table">${rows.map(r=>`<div><b>${r[0]}</b><span>${r[1]}</span></div>`).join('')}</div></section>`;}
function scenarioLine(code){const lines={
'DS-01':'Observe que cada nó tem estado e falhas próprias: não há memória ou clock global mágico.',
'DS-02':'O usuário deve perceber um sistema único, mesmo com migração, réplicas e escala.',
'DS-03':'Compare papéis: cliente-servidor, múltiplos servidores, proxy e P2P.',
'DS-04':'Siga a mensagem pelas camadas e pelo handshake antes de diagnosticar o chat.',
'DS-05':'A chamada parece local, mas a rede introduz latência, exceções e validação.',
'DS-06':'Use uma camada de indireção para separar produtores e consumidores no espaço e no tempo.',
'DS-07':'A fila protege o sistema contra rajadas e desacopla a velocidade de entrada/saída.',
'DS-08':'Cada ACK gera a necessidade de outro ACK: confiança aumenta, certeza não.',
'DS-09':'Nós maliciosos podem enviar mensagens diferentes para participantes diferentes.',
'DS-10':'Algoritmos distribuídos só funcionam se as suposições do modelo forem verdadeiras.',
'DS-11':'Disponibilidade é medida por tempo funcionando e por objetivos contratuais.',
'DS-12':'Middleware separa preocupações e ajuda sistemas heterogêneos a conversar.',
'DS-13':'REST manipula recursos; SOAP descreve operações e mensagens XML estruturadas.',
'DS-14':'O overlay localiza objetos por GUIDs mesmo quando peers entram e saem.',
'DS-15':'Combine padrões: redundância, fila, P2P, modelo de falhas e monitoramento.',
'DS-16':'Escolha blocos de código para conectar cliente, proxy, API, fila, banco, monitoramento e P2P em um único sistema jogável.'};return lines[code]||''}
function highlight(s){return s.replace(/(target|model|network|node|timing|DHT API|REST|SOAP|availability|objectives|middleware layer)/g,'<span class="k">$1</span>').replace(/(ok|live|reliable|put|get|remove|GET|POST|SYN|ACK)/gi,'<span class="ok">$1</span>').replace(/(timeout|message_loss|server_crash|partition|Byzantine|bad|lost|Fault)/gi,'<span class="bad">$1</span>')}
function answer(i){if(state.answered)return;state.answered=true;const m=MISSIONS[state.mission];const st=m.steps[state.step];document.querySelectorAll('.opt').forEach((b,idx)=>{b.disabled=true;if(idx===st.a)b.classList.add('correct');if(idx===i&&i!==st.a)b.classList.add('wrong')});const ok=i===st.a;const fb=$('#feedback');fb.classList.add('show');fb.innerHTML=(ok?'✅ <b>Correto.</b> ':'❌ <b>Quase.</b> ')+st.why; if(ok){state.score+=10+Math.min(state.streak,5)*2;state.streak++;toast('Conceito consolidado + pontos');}else{state.score=Math.max(0,state.score-3);state.streak=0;toast('Revise o conceito e avance');}const cur=state.done[m.code]||0;if(ok&&state.step+1>cur)state.done[m.code]=state.step+1;save();$('#next').style.display='inline-flex';}
function advance(){const m=MISSIONS[state.mission];if(state.step<m.steps.length-1){state.step++;state.answered=false;save();renderMission();return;}if(state.mission<MISSIONS.length-1){state.mission++;state.step=0;state.answered=false;save();renderShell();renderMission();document.getElementById('main').scrollIntoView({behavior:'smooth'});return;}win();}
function win(){const main=document.getElementById('main');main.innerHTML=`<article class="panel win-card"><div class="eyebrow">Architect Mode concluído</div><h2>Você salvou a Nebula Cloud.</h2><p style="color:var(--muted);line-height:1.7;max-width:720px;margin:0 auto 20px">Você passou por introdução, arquitetura, comunicação, modelos de falha, middleware, web services e P2P. Pontuação final: <b style="color:var(--cyan)">${state.score}</b>.</p><button class="btn primary" onclick="localStorage.removeItem('nebula-ds-state');location.reload()">Jogar novamente</button></article>`;}
load();renderShell();renderMission();
